use std::sync::Arc;

use arrow::array::{Float64Array, Int64Array, RecordBatch, StringArray};
use arrow::datatypes::{DataType, Field, Schema};
use datafusion::logical_expr::col;
use datafusion::physical_plan::common::collect_sendable_stream;
use datafusion::prelude::SessionContext;
use deltalake_core::{DeltaTable, protocol::SaveMode};
use tempfile::TempDir;
use url::Url;

fn make_batch(group: &str) -> RecordBatch {
    let schema = Arc::new(Schema::new(vec![
        Field::new("group", DataType::Utf8, false),
        Field::new("region", DataType::Utf8, false),
        Field::new("ts", DataType::Int64, false),
        Field::new("val", DataType::Float64, false),
    ]));
    RecordBatch::try_new(
        schema,
        vec![
            Arc::new(StringArray::from(vec![group, group, group])),
            Arc::new(StringArray::from(vec!["A", "B", "C"])),
            Arc::new(Int64Array::from(vec![1_704_067_200_000_000_i64; 3])),
            Arc::new(Float64Array::from(vec![1.0, 2.0, 3.0])),
        ],
    )
    .unwrap()
}

async fn row_count(table: &DeltaTable) -> usize {
    let (_table, stream) = table.clone().scan_table().await.unwrap();
    collect_sendable_stream(stream)
        .await
        .unwrap()
        .iter()
        .map(|batch| batch.num_rows())
        .sum()
}

async fn run(group: &str) {
    let tempdir = TempDir::new().unwrap();
    let url = Url::from_directory_path(tempdir.path()).unwrap();
    let batch = make_batch(group);
    let table = DeltaTable::try_from_url(url).await.unwrap()
        .write([batch.clone()])
        .with_save_mode(SaveMode::ErrorIfExists)
        .with_partition_columns(["group"])
        .await
        .unwrap();

    let ctx = SessionContext::new();
    let source = ctx.read_batch(batch).unwrap();
    let predicate = col("target.group")
        .eq(col("source.group"))
        .and(col("target.region").eq(col("source.region")))
        .and(col("target.ts").eq(col("source.ts")));
    let (table, metrics) = table
        .merge(source, predicate)
        .with_source_alias("source")
        .with_target_alias("target")
        .when_matched_update(|update| update.update("val", col("source.val")))
        .unwrap()
        .await
        .unwrap();

    println!("{group:?}: rows={}, files_removed={}, updated={}", row_count(&table).await, metrics.num_target_files_removed, metrics.num_target_rows_updated);
}

#[tokio::main]
async fn main() {
    run("foo bar").await;
    run("foo_bar").await;
}
